package genxsolution.vms.vmsbackend.vehicle_management.vehicle_running_log.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_running_log.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_running_log.service.VehicleRunningLogService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/running-logs") public class VehicleRunningLogController { private final VehicleRunningLogService service; public VehicleRunningLogController(VehicleRunningLogService service){this.service=service;} @GetMapping public List<VehicleRunningLogResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleRunningLogResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleRunningLogResponse create(@RequestBody VehicleRunningLogUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleRunningLogResponse update(@PathVariable UUID id,@RequestBody VehicleRunningLogUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
